INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (1,1,'I have car.','I have a car.','차 한 대 → a 필수 (셀 수 있는 명사)');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (2,1,'I am have a question.','I have a question.','have가 동사, am 빼기');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (3,1,'She have two sisters.','She has two sisters.','3인칭 단수 → has');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (4,1,'I have a homework.','I have homework.','homework는 셀 수 없음 → a 없이');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (5,2,'I get new shoes yesterday.','I got new shoes yesterday.','yesterday → 과거 got');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (6,2,'It get dark.','It''s getting dark.','변하는 중 → 진행형 (is getting)');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (7,2,'I get to home.','I get home.','home 앞엔 to 없음 (부사)');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (8,2,'He get angry.','He got angry.','이미 화남 → 과거 got');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (9,3,'How long it takes?','How long does it take?','의문문 → does + 동사원형');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (10,3,'I take a picture yesterday.','I took a picture yesterday.','과거 → took');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (11,3,'Take a your time.','Take your time.','your 앞에 a 없음');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (12,3,'It take 10 minutes.','It takes 10 minutes.','3인칭 단수 it → takes');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (13,4,'You make me to laugh.','You make me laugh.','make + 목적어 + 동사원형 (to 없음)');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (14,4,'I make a mistake yesterday.','I made a mistake yesterday.','과거 → made');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (15,4,'That make me happy.','That makes me happy.','That(3인칭) → makes');
INSERT INTO traps (id,verb_id,wrong_ex,right_ex,why) VALUES (16,4,'Let''s make a dinner.','Let''s make dinner.','식사 dinner는 보통 a 없이');
INSERT INTO stage0_items (id,name,concept,examples,order_no) VALUES (1,'뼈대 1 — 주어 + 동사는 반드시 있다','한국어는 ''배고파''로 끝나지만, 영어는 ''누가(주어) + 어쩐다(동사)''가 항상 있어야 그림이 완성됨','[{"wrong": "Hungry.", "right": "I am hungry.", "why": "누가 배고픈지(I) + 상태(am) 둘 다 필요"}, {"wrong": "Go now.", "right": "I will go now.", "why": "명령이 아니면 주어(I) 필수"}, {"wrong": "So tired.", "right": "I''m so tired.", "why": "감정도 주어+be동사로 시작"}, {"wrong": "Rain a lot.", "right": "It rains a lot.", "why": "비가 와도 주어 It 필요 (영어는 빈자리 안 둠)"}]'::jsonb,1);
INSERT INTO stage0_items (id,name,concept,examples,order_no) VALUES (2,'뼈대 2 — be동사와 일반동사는 못 섞는다','한 문장에 진짜 동사는 하나. be(am/is/are)는 ''상태'', 일반동사는 ''행동''. 둘을 같이 쓰면 충돌','[{"wrong": "I am have a car.", "right": "I have a car.", "why": "have가 동사니까 am 불필요"}, {"wrong": "I am go to work.", "right": "I go to work.", "why": "go가 동사. am 빼기"}, {"wrong": "She is have lunch.", "right": "She is having lunch.", "why": "굳이 is 쓰려면 동사를 -ing로 (진행형)"}, {"wrong": "I hungry.", "right": "I am hungry.", "why": "hungry는 형용사라 동사 am 필요"}]'::jsonb,2);
INSERT INTO stage0_items (id,name,concept,examples,order_no) VALUES (3,'뼈대 3 — 셀 수 있는 명사엔 a / the가 붙는다','한국어엔 없는 개념. ''a''는 ''하나의(아무거나)'', ''the''는 ''바로 그것''. 명사 앞 빈자리를 못 둠','[{"wrong": "I have car.", "right": "I have a car.", "why": "차 ''한 대'' — a가 ''하나''라는 그림"}, {"wrong": "I''m teacher.", "right": "I''m a teacher.", "why": "직업 앞엔 a (여럿 중 하나)"}, {"wrong": "Close door.", "right": "Close the door.", "why": "서로 아는 ''바로 그 문'' — the"}, {"wrong": "I like dog.", "right": "I like dogs.", "why": "개 전체를 좋아하면 복수 (a도 the도 없이)"}]'::jsonb,3);
INSERT INTO stage0_items (id,name,concept,examples,order_no) VALUES (4,'뼈대 4 — 한국어 ''있다''는 영어로 3가지','''있다''를 무조건 have로 쓰면 안 됨. 소유면 have, 위치면 there is, 사람 위치면 be','[{"wrong": "There is a friend. (친구 있어)", "right": "I have a friend.", "why": "내가 가진 관계 → have"}, {"wrong": "I have a book on the desk.", "right": "There is a book on the desk.", "why": "어떤 장소에 존재 → there is"}, {"wrong": "I have at home.", "right": "I''m at home.", "why": "내가 어떤 장소에 → be동사"}, {"wrong": "Have a problem here.", "right": "There''s a problem here.", "why": "문제가 존재함 → there is"}]'::jsonb,4);
